<span class="line">      <span class="token keyword">throw</span> <span class="token keyword">new</span> <span class="token class-name">Error</span><span class="token punctuation">(</span><span class="token string">&quot;Missing required fields: name or content&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
